INSERT INTO Companies (company_name, description, location, logo_path) VALUES
('VNG Corporation', 'VNG là tập đoàn công nghệ hàng đầu Việt Nam, chuyên về Zalo, ZaloPay, và trò chơi trực tuyến. Với hơn 2.000 nhân viên, chúng tôi cam kết xây dựng môi trường sáng tạo.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/vng.png'),
('FPT Software', 'FPT Software là công ty phần mềm lớn nhất Việt Nam, phục vụ khách hàng toàn cầu với hơn 20.000 nhân viên tại 29 quốc gia.', 'Hà Nội, Việt Nam', '/logos/fptsoftware.png'),
('Vinmec International Hospital', 'Vinmec cung cấp dịch vụ y tế chất lượng cao với công nghệ tiên tiến và đội ngũ bác sĩ chuyên môn cao.', 'Đà Nẵng, Việt Nam', '/logos/vinmec.png'),
('Tiki Corporation', 'Tiki là nền tảng thương mại điện tử hàng đầu, cung cấp hàng triệu sản phẩm từ sách đến đồ điện tử.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/tiki.png'),
('Shopee Vietnam', 'Shopee là sàn thương mại điện tử lớn nhất Đông Nam Á, tìm kiếm nhân tài để phát triển công nghệ.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/shopee.png'),
('Techcombank', 'Techcombank là ngân hàng thương mại hàng đầu, cung cấp giải pháp tài chính toàn diện.', 'Hà Nội, Việt Nam', '/logos/techcombank.png'),
('Viettel Solutions', 'Viettel Solutions cung cấp giải pháp công nghệ thông tin và viễn thông, thuộc Tập đoàn Viettel.', 'Hà Nội, Việt Nam', '/logos/viettel.png'),
('Grab Vietnam', 'Grab là siêu ứng dụng Đông Nam Á, cung cấp dịch vụ gọi xe, giao hàng, và thanh toán.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/grab.png'),
('TMA Solutions', 'TMA Solutions là công ty gia công phần mềm lớn với hơn 3.000 kỹ sư, phục vụ khách hàng toàn cầu.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/tma.png'),
('Lazada Vietnam', 'Lazada là nền tảng thương mại điện tử, cung cấp trải nghiệm mua sắm đa dạng.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/lazada.png'),
('VPBank', 'VPBank là ngân hàng thương mại hàng đầu, cung cấp sản phẩm tài chính sáng tạo.', 'Hà Nội, Việt Nam', '/logos/vpbank.png'),
('Mobifone', 'Mobifone là nhà mạng viễn thông lớn, cung cấp dịch vụ di động và giải pháp công nghệ.', 'Hà Nội, Việt Nam', '/logos/mobifone.png'),
('Haravan', 'Haravan cung cấp giải pháp thương mại điện tử và bán lẻ omnichannel cho doanh nghiệp.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/haravan.png'),
('VNG Cloud', 'VNG Cloud cung cấp giải pháp điện toán đám mây, hỗ trợ doanh nghiệp chuyển đổi số.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/vngcloud.png'),
('VinHomes', 'VinHomes là công ty bất động sản hàng đầu, phát triển các dự án đô thị hiện đại.', 'Hà Nội, Việt Nam', '/logos/vinhomes.png'),
('Sendo', 'Sendo là sàn thương mại điện tử Việt Nam, cung cấp hàng hóa đa dạng.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/sendo.png'),
('KMS Technology', 'KMS Technology là công ty phát triển phần mềm, phục vụ doanh nghiệp toàn cầu.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/kms.png'),
('ACB', 'ACB là ngân hàng thương mại cổ phần, cung cấp giải pháp tài chính hiện đại.', 'Hà Nội, Việt Nam', '/logos/acb.png'),
('Zalo', 'Zalo là ứng dụng nhắn tin và mạng xã hội lớn nhất Việt Nam, thuộc VNG.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/zalo.png'),
('VinFast', 'VinFast là công ty sản xuất ô tô và xe máy điện, thuộc Vingroup.', 'Hà Nội, Việt Nam', '/logos/vinfast.png'),
('FWD Vietnam', 'FWD là công ty bảo hiểm quốc tế, cung cấp sản phẩm bảo hiểm nhân thọ.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/fwd.png'),
('Be Group', 'Be Group là siêu ứng dụng Việt Nam, cung cấp dịch vụ gọi xe và giao hàng.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/be.png'),
('Sun Group', 'Sun Group đầu tư vào bất động sản, du lịch và giải trí với các dự án lớn.', 'Đà Nẵng, Việt Nam', '/logos/sungroup.png'),
('Topica Edtech Group', 'Topica cung cấp khóa học trực tuyến chất lượng cao trong lĩnh vực giáo dục.', 'Hà Nội, Việt Nam', '/logos/topica.png'),
('Gameloft Vietnam', 'Gameloft phát triển trò chơi di động với đội ngũ sáng tạo tại Việt Nam.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/gameloft.png'),
('VIB Bank', 'VIB là ngân hàng thương mại cổ phần, cung cấp giải pháp tài chính hiện đại.', 'Hà Nội, Việt Nam', '/logos/vib.png'),
('RMIT Vietnam', 'RMIT Vietnam là trường đại học quốc tế, cung cấp giáo dục chất lượng cao.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/rmit.png'),
('PwC Vietnam', 'PwC là công ty kiểm toán và tư vấn, phục vụ doanh nghiệp toàn cầu.', 'Hà Nội, Việt Nam', '/logos/pwc.png'),
('Unilever Vietnam', 'Unilever là tập đoàn hàng tiêu dùng nhanh, cung cấp sản phẩm như Dove, Omo.', 'TP. Hồ Chí Minh, Việt Nam', '/logos/unilever.png'),
('Nestlé Vietnam', 'Nestlé là công ty thực phẩm và đồ uống lớn nhất thế giới, có chi nhánh tại Việt Nam.', 'Hà Nội, Việt Nam', '/logos/nestle.png');
INSERT INTO Jobs (company_id, title, description, location, category, job_type, experience_level, salary, remote_option, qualifications, perks, date_posted, application_deadline) VALUES
(1, 'Kỹ sư Phần mềm Cao cấp', 'VNG đang tìm kiếm Kỹ sư Phần mềm Cao cấp để phát triển hệ thống backend cho ZaloPay. Bạn sẽ thiết kế API hiệu quả, tối ưu hóa cơ sở dữ liệu MySQL, và tích hợp với AWS. Làm việc cùng đội ngũ kỹ sư tài năng, bạn sẽ đóng góp vào sản phẩm có hàng triệu người dùng. Yêu cầu: 5+ năm kinh nghiệm với Java hoặc Go, kinh nghiệm với microservices và hệ thống phân tán.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Senior', '40-60 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n5+ năm kinh nghiệm Java/Go\nBiết AWS', 'Thưởng hiệu suất\nBảo hiểm sức khỏe\n15 ngày phép', NOW(), '2025-07-18'),
(2, 'Chuyên viên Marketing Số', 'FPT Software cần Chuyên viên Marketing Số để xây dựng chiến dịch quảng cáo trực tuyến và tối ưu SEO/SEM. Bạn sẽ quản lý Google Ads, phân tích dữ liệu với Google Analytics, và phối hợp với đội thiết kế. Cơ hội làm việc với khách hàng quốc tế tại Nhật, Mỹ. Yêu cầu: 3+ năm kinh nghiệm, thành thạo Google Analytics.', 'Hà Nội', 'Marketing', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Marketing\n3+ năm kinh nghiệm\nThành thạo Google Analytics', 'Bảo hiểm\nDu lịch công ty\nĐào tạo quốc tế', NOW(), '2025-07-20'),
(3, 'Bác sĩ Đa khoa', 'Vinmec cần Bác sĩ Đa khoa để khám và điều trị bệnh nhân tại Đà Nẵng. Bạn sẽ sử dụng thiết bị y tế hiện đại, tham gia hội thảo chuyên môn, và phối hợp với đội ngũ y tá. Yêu cầu: Tốt nghiệp ĐH Y, 3+ năm kinh nghiệm, có chứng chỉ hành nghề.', 'Đà Nẵng', 'Healthcare', 'Full-time', 'Mid', '30-50 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Y\n3+ năm kinh nghiệm\nChứng chỉ hành nghề', 'Bảo hiểm y tế\nHỗ trợ nhà ở\nĐào tạo', NOW(), '2025-07-15'),
(4, 'Nhân viên Kho', 'Tiki cần Nhân viên Kho để quản lý hàng hóa và đảm bảo giao hàng đúng hạn. Bạn sẽ kiểm tra tồn kho, đóng gói sản phẩm, và sử dụng hệ thống quản lý kho. Yêu cầu: Tốt nghiệp THPT, sức khỏe tốt, cẩn thận trong công việc.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Entry', '10-15 triệu VND', 'Onsite', 'Tốt nghiệp THPT\nSức khỏe tốt', 'Thưởng lễ\nBảo hiểm\nHỗ trợ ăn trưa', NOW(), '2025-07-10'),
(5, 'Kỹ sư AI', 'Shopee cần Kỹ sư AI để phát triển hệ thống gợi ý sản phẩm. Bạn sẽ làm việc với Python, TensorFlow, và xử lý big data. Yêu cầu: 3+ năm kinh nghiệm AI, tốt nghiệp ĐH CNTT, có kinh nghiệm với machine learning.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Mid', '30-50 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n3+ năm kinh nghiệm AI\nBiết TensorFlow', 'Thưởng dự án\nLaptop hỗ trợ\n12 ngày phép', NOW(), '2025-07-25'),
(6, 'Chuyên viên Tín dụng', 'Techcombank cần Chuyên viên Tín dụng để thẩm định hồ sơ vay. Bạn sẽ tư vấn khách hàng, phân tích tài chính, và đảm bảo tuân thủ quy định. Yêu cầu: Tốt nghiệp ĐH Tài chính, 2+ năm kinh nghiệm.', 'Hà Nội', 'Finance', 'Full-time', 'Mid', '20-35 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Tài chính\n2+ năm kinh nghiệm', 'Thưởng cuối năm\nBảo hiểm\nĐào tạo', NOW(), '2025-07-12'),
(7, 'Kỹ sư Viễn thông', 'Viettel Solutions cần Kỹ sư Viễn thông để triển khai hệ thống mạng 5G. Bạn sẽ thiết kế hạ tầng, tối ưu hiệu suất mạng, và xử lý sự cố. Yêu cầu: Tốt nghiệp ĐH Viễn thông, 3+ năm kinh nghiệm.', 'Hà Nội', 'IT_Software', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Viễn thông\n3+ năm kinh nghiệm', 'Bảo hiểm\nHỗ trợ nhà ở\nDu lịch', NOW(), '2025-07-18'),
(8, 'Nhân viên Hỗ trợ Khách hàng', 'Grab cần Nhân viên Hỗ trợ Khách hàng để giải quyết thắc mắc qua hotline và email. Bạn sẽ hỗ trợ khách hàng về dịch vụ gọi xe, giao hàng. Yêu cầu: Tốt nghiệp THPT, giao tiếp tốt.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Entry', '10-15 triệu VND', 'Onsite', 'Tốt nghiệp THPT\nGiao tiếp tốt', 'Thưởng KPI\nBảo hiểm\nHỗ trợ ăn trưa', NOW(), '2025-07-10'),
(9, 'Lập trình viên Mobile', 'TMA Solutions cần Lập trình viên Mobile để phát triển ứng dụng iOS/Android. Bạn sẽ làm việc với Flutter hoặc React Native, đảm bảo chất lượng sản phẩm. Yêu cầu: 2+ năm kinh nghiệm mobile.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Mid', '20-35 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n2+ năm kinh nghiệm mobile', 'Thưởng dự án\nBảo hiểm\nĐào tạo', NOW(), '2025-07-20'),
(10, 'Quản lý Kho', 'Lazada cần Quản lý Kho để giám sát hoạt động kho bãi, tối ưu quy trình, và quản lý đội nhóm. Bạn sẽ đảm bảo hàng hóa được xử lý nhanh chóng. Yêu cầu: Tốt nghiệp ĐH, 3+ năm kinh nghiệm quản lý kho.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Mid', '20-30 triệu VND', 'Onsite', 'Tốt nghiệp ĐH\n3+ năm kinh nghiệm quản lý kho', 'Thưởng hiệu suất\nBảo hiểm\nHỗ trợ ăn uống', NOW(), '2025-07-15'),
(11, 'Chuyên viên Quan hệ Khách hàng', 'VPBank cần Chuyên viên Quan hệ Khách hàng để tư vấn sản phẩm tài chính, chăm sóc khách hàng VIP. Yêu cầu: Tốt nghiệp ĐH Kinh tế, 2+ năm kinh nghiệm.', 'Hà Nội', 'Finance', 'Full-time', 'Mid', '18-30 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Kinh tế\n2+ năm kinh nghiệm', 'Thưởng doanh số\nBảo hiểm\nĐào tạo', NOW(), '2025-07-12'),
(12, 'Kỹ sư Hệ thống', 'Mobifone cần Kỹ sư Hệ thống để quản lý hạ tầng mạng, làm việc với Linux, Docker. Yêu cầu: Tốt nghiệp ĐH CNTT, 3+ năm kinh nghiệm hệ thống.', 'Hà Nội', 'IT_Software', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH CNTT\n3+ năm kinh nghiệm', 'Bảo hiểm\nHỗ trợ nhà ở\nDu lịch', NOW(), '2025-07-18'),
(13, 'Chuyên viên Thương mại Điện tử', 'Haravan cần Chuyên viên Thương mại Điện tử để hỗ trợ khách hàng triển khai website bán hàng. Yêu cầu: Tốt nghiệp ĐH Marketing, 2+ năm kinh nghiệm.', 'TP. Hồ Chí Minh', 'Marketing', 'Full-time', 'Mid', '20-30 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH Marketing\n2+ năm kinh nghiệm', 'Thưởng dự án\nBảo hiểm\nĐào tạo', NOW(), '2025-07-20'),
(14, 'Kỹ sư DevOps', 'VNG Cloud cần Kỹ sư DevOps để triển khai hệ thống CI/CD, làm việc với Kubernetes, AWS. Yêu cầu: Tốt nghiệp ĐH CNTT, 3+ năm kinh nghiệm DevOps.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Mid', '30-50 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n3+ năm kinh nghiệm DevOps', 'Thưởng hiệu suất\nLaptop hỗ trợ\n15 ngày phép', NOW(), '2025-07-25'),
(15, 'Nhân viên Kinh doanh Bất động sản', 'VinHomes cần Nhân viên Kinh doanh để tư vấn bán căn hộ, chăm sóc khách hàng. Yêu cầu: Tốt nghiệp THPT, giao tiếp tốt.', 'Hà Nội', 'Marketing', 'Full-time', 'Entry', '15-30 triệu VND', 'Onsite', 'Tốt nghiệp THPT\nGiao tiếp tốt', 'Thưởng hoa hồng\nBảo hiểm\nĐào tạo', NOW(), '2025-07-15'),
(16, 'Nhân viên Hỗ trợ Khách hàng', 'Sendo cần Nhân viên Hỗ trợ để xử lý khiếu nại khách hàng qua email, điện thoại. Yêu cầu: Tốt nghiệp THPT, giao tiếp tốt.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Entry', '10-15 triệu VND', 'Onsite', 'Tốt nghiệp THPT\nGiao tiếp tốt', 'Thưởng KPI\nBảo hiểm\nHỗ trợ ăn trưa', NOW(), '2025-07-10'),
(17, 'Lập trình viên Backend', 'KMS Technology cần Lập trình viên Backend để phát triển hệ thống với Node.js, Java. Yêu cầu: Tốt nghiệp ĐH CNTT, 3+ năm kinh nghiệm.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Mid', '25-40 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n3+ năm kinh nghiệm', 'Thưởng dự án\nBảo hiểm\nĐào tạo quốc tế', NOW(), '2025-07-20'),
(18, 'Chuyên viên Kế toán', 'ACB cần Chuyên viên Kế toán để xử lý báo cáo tài chính, kiểm soát chi phí. Yêu cầu: Tốt nghiệp ĐH Kế toán, 2+ năm kinh nghiệm.', 'Hà Nội', 'Finance', 'Full-time', 'Mid', '20-35 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Kế toán\n2+ năm kinh nghiệm', 'Thưởng cuối năm\nBảo hiểm\nĐào tạo', NOW(), '2025-07-12'),
(19, 'Nhân viên Nội dung', 'Zalo cần Nhân viên Nội dung để phát triển nội dung cho mạng xã hội, tạo bài viết thu hút. Yêu cầu: Tốt nghiệp ĐH Truyền thông, 2+ năm kinh nghiệm.', 'TP. Hồ Chí Minh', 'Marketing', 'Full-time', 'Mid', '20-30 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH Truyền thông\n2+ năm kinh nghiệm', 'Thưởng sáng tạo\nBảo hiểm\nHỗ trợ thiết bị', NOW(), '2025-07-20'),
(20, 'Kỹ sư Cơ khí', 'VinFast cần Kỹ sư Cơ khí để thiết kế linh kiện ô tô, làm việc với phần mềm CAD. Yêu cầu: Tốt nghiệp ĐH Cơ khí, 3+ năm kinh nghiệm.', 'Hà Nội', 'Government_Public_Sector', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Cơ khí\n3+ năm kinh nghiệm', 'Bảo hiểm\nHỗ trợ nhà ở\nĐào tạo', NOW(), '2025-07-30'),
(21, 'Chuyên viên Bảo hiểm', 'FWD cần Chuyên viên Bảo hiểm để tư vấn sản phẩm bảo hiểm nhân thọ. Yêu cầu: Tốt nghiệp ĐH, giao tiếp tốt, kỹ năng bán hàng.', 'TP. Hồ Chí Minh', 'Finance', 'Full-time', 'Entry', '15-25 triệu VND', 'Onsite', 'Tốt nghiệp ĐH\nGiao tiếp tốt', 'Thưởng hoa hồng\nBảo hiểm\nDu lịch', NOW(), '2025-07-15'),
(22, 'Nhân viên Giao hàng', 'Be Group cần Nhân viên Giao hàng để giao thực phẩm, hàng hóa. Yêu cầu: Có xe máy, sức khỏe tốt.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Entry', '10-15 triệu VND', 'Onsite', 'Có xe máy\nSức khỏe tốt', 'Thưởng KPI\nHỗ trợ xăng xe', NOW(), '2025-07-10'),
