(24, 'Giảng viên Tiếng Anh', 'Topica cần Giảng viên Tiếng Anh để dạy học trực tuyến. Yêu cầu: Tốt nghiệp ĐH Sư phạm, 2+ năm kinh nghiệm giảng dạy.', 'Hà Nội', 'Government_Public_Sector', 'Part-time', 'Mid', '15-25 triệu VND', 'Remote', 'Tốt nghiệp ĐH Sư phạm\n2+ năm kinh nghiệm', 'Thưởng giảng dạy\nHỗ trợ thiết bị', NOW(), '2025-07-20'),
(25, 'Lập trình viên Game', 'Gameloft cần Lập trình viên Game để phát triển trò chơi di động với Unity. Yêu cầu: Tốt nghiệp ĐH CNTT, 2+ năm kinh nghiệm Unity.', 'TP. Hồ Chí Minh', 'IT_Software', 'Full-time', 'Mid', '20-35 triệu VND', 'Hybrid', 'Tốt nghiệp ĐH CNTT\n2+ năm kinh nghiệm Unity', 'Thưởng dự án\nBảo hiểm\nĐào tạo', NOW(), '2025-07-20'),
(26, 'Chuyên viên Tín dụng Cá nhân', 'VIB cần Chuyên viên Tín dụng để thẩm định hồ sơ vay cá nhân. Yêu cầu: Tốt nghiệp ĐH Tài chính, 2+ năm kinh nghiệm.', 'Hà Nội', 'Finance', 'Full-time', 'Mid', '20-30 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Tài chính\n2+ năm kinh nghiệm', 'Thưởng doanh số\nBảo hiểm\nĐào tạo', NOW(), '2025-07-12'),
(27, 'Nhân viên Hành chính', 'RMIT Vietnam cần Nhân viên Hành chính để hỗ trợ quản lý văn phòng, xử lý tài liệu. Yêu cầu: Tốt nghiệp ĐH, 2+ năm kinh nghiệm.', 'TP. Hồ Chí Minh', 'Government_Public_Sector', 'Full-time', 'Mid', '15-25 triệu VND', 'Onsite', 'Tốt nghiệp ĐH\n2+ năm kinh nghiệm', 'Bảo hiểm\nHỗ trợ học phí\nĐào tạo', NOW(), '2025-07-15'),
(28, 'Chuyên viên Kiểm toán', 'PwC cần Chuyên viên Kiểm toán để kiểm tra báo cáo tài chính khách hàng. Yêu cầu: Tốt nghiệp ĐH Kế toán, 3+ năm kinh nghiệm.', 'Hà Nội', 'Finance', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Kế toán\n3+ năm kinh nghiệm', 'Thưởng dự án\nBảo hiểm\nĐào tạo quốc tế', NOW(), '2025-07-20'),
(29, 'Chuyên viên Trade Marketing', 'Unilever cần Chuyên viên Trade Marketing để xây dựng chiến lược bán hàng. Yêu cầu: Tốt nghiệp ĐH Marketing, 3+ năm kinh nghiệm.', 'TP. Hồ Chí Minh', 'Marketing', 'Full-time', 'Mid', '25-40 triệu VND', 'Onsite', 'Tốt nghiệp ĐH Marketing\n3+ năm kinh nghiệm', 'Thưởng hiệu suất\nBảo hiểm\nĐào tạo', NOW(), '2025-07-20'),
